import React, { useEffect, useRef, useState } from "react";
import First from "../pages/First";
import Second from "../pages/Second";
import Third from "../pages/Third";
import Four from "../pages/Four";
import Zero from "../pages/zero";
import Five from "../pages/Five";
import Six from "../pages/Six";
import music from "../Assets/Shubham.mp3";

const MainPage = () => {
  const [step, setStep] = useState(0);
  const [audioStarted, setAudioStarted] = useState(false);
  const audioRef = useRef(null);

  // ⏱️ Step transitions
  useEffect(() => {
    const timers = [
      setTimeout(() => setStep(1), 2000),
      setTimeout(() => setStep(2), 14000),
      setTimeout(() => setStep(3), 21000),
      setTimeout(() => setStep(4), 28000), // ✅ FIXED
      setTimeout(() => setStep(5), 35000),
      setTimeout(() => setStep(6), 40000),
    ];

    return () => timers.forEach(clearTimeout);
  }, []);

  // 🎵 Start audio on first user interaction
  const handleStartAudio = () => {
    if (audioRef.current && !audioStarted) {
      audioRef.current.muted = false;
      audioRef.current.volume = 0.5;

      audioRef.current
        .play()
        .then(() => {
          setAudioStarted(true);
        })
        .catch((err) => console.log("Audio play failed:", err));
    }
  };

  return (
    <div className="background-container bg-[#FFFCF8] min-h-screen">
      
      {/* 🎵 Audio */}
      <audio ref={audioRef} autoPlay loop muted>
        <source src={music} type="audio/mp3" />
      </audio>

      {/* 🚀 Start Screen (Required for autoplay policy) */}
      {!audioStarted && (
        <div
          onClick={handleStartAudio}
          className="fixed inset-0 flex items-center justify-center bg-black text-white z-50 cursor-pointer"
        >
          <h1 className="text-xl animate-pulse">
            Tap Anywhere to Start 🎵
          </h1>
        </div>
      )}

      {/* 📱 Pages */}
      {step === 0 && <Zero />}
      {step === 1 && <First />}
      {step === 2 && <Second />}
      {step === 3 && <Third />}
      {step === 4 && <Four />}
      {step === 5 && <Five />}
      {step === 6 && <Six />}
    </div>
  );
};

export default MainPage;